const input = $input.first().json.body || {};
const limit = input.limit || 1000;
const batchSize = input.batch_size || 50;
const targetWorkflowUrl = input.target_webhook || '{{ $env.WEBHOOK_BASE_URL }}/webhook/client-lookup-test';

const testCases = [];
let id = 1;

// Generate 1000 test cases across 5 categories (200 each)
// Mock workflow returns client: null, so expected_client_found = 'false'
for (let i = 0; i < 200; i++) {
  testCases.push({id: id++, category: 'client_lookup', input_phone: `+1555${String(1000000 + i).slice(-7)}`, expected_success: 'true', expected_client_found: 'false'});
}
for (let i = 0; i < 200; i++) {
  testCases.push({id: id++, category: 'phone_format', input_phone: `+1555${String(2000000 + i).slice(-7)}`, expected_success: 'true', expected_client_found: 'false'});
}
for (let i = 0; i < 200; i++) {
  const errInputs = ['', ' ', 'invalid', 'abc', '<script>', '{}', '[]', 'null', 'undef', 'NaN', '000', '---', '...', '@#$', 'phone', 'test', '!@#', '()', '[]{}', 'DROP', 'SELECT', '--', '/*', '*/', 'admin', 'root', 'password', '1234', 'true', 'false', 'OR 1=1', '; DROP', 'undefined', 'function', 'eval', 'exec', 'system', 'rm -rf', 'cmd', 'shell', 'bash', 'sh', 'python', 'node', 'require', 'import', 'export', 'process', 'Buffer', 'fs', 'child_process', 'fetch', 'XMLHttpRequest', 'document', 'window', 'alert', 'prompt', 'confirm', 'console', 'log', 'error', 'warn', 'debug', 'trace', 'info', 'dir', 'table', 'clear', 'count', 'assert', 'time', 'timeEnd', 'group', 'groupEnd', 'profile', 'profileEnd', 'mark', 'measure', 'memory', 'exception', 'createObjectURL', 'revokeObjectURL', 'URL', 'Blob', 'File', 'FileReader', 'FormData', 'Headers', 'Request', 'Response', 'AbortController', 'AbortSignal', 'Worker', 'SharedWorker', 'ServiceWorker', 'BroadcastChannel', 'MessageChannel', 'MessagePort', 'WebSocket', 'EventSource', 'XMLHttpRequest', 'fetch', 'cache', 'indexedDB', 'localStorage', 'sessionStorage', 'cookie', 'navigator', 'location', 'history', 'screen', 'crypto', 'performance', 'Intl', 'Date', 'JSON', 'Math', 'Number', 'String', 'Array', 'Object', 'Function', 'Symbol', 'BigInt', 'Map', 'Set', 'WeakMap', 'WeakSet', 'Promise', 'Proxy', 'Reflect', 'Error', 'TypeError', 'RangeError', 'SyntaxError', 'ReferenceError', 'URIError', 'EvalError', 'AggregateError', 'InternalError', 'RegExp', 'ArrayBuffer', 'SharedArrayBuffer', 'DataView', 'Int8Array', 'Uint8Array', 'Uint8ClampedArray', 'Int16Array', 'Uint16Array', 'Int32Array', 'Uint32Array', 'Float32Array', 'Float64Array', 'BigInt64Array', 'BigUint64Array', 'Atomics', 'Generator', 'AsyncGenerator', 'Iterator', 'AsyncIterator', 'NaN', 'Infinity', '-Infinity', 'null', 'undefined'];
  testCases.push({id: id++, category: 'error_handling', input_phone: errInputs[i % errInputs.length], expected_success: 'true', expected_client_found: 'false'});
}
for (let i = 0; i < 200; i++) {
  testCases.push({id: id++, category: 'integration', input_phone: `+1555${String(4000000 + i).slice(-7)}`, input_email: `test${i}@example.com`, expected_success: 'true', expected_client_found: 'false'});
}
for (let i = 0; i < 200; i++) {
  testCases.push({id: id++, category: 'stress_test', input_phone: `+1555${String(5000000 + i).slice(-7)}`, expected_success: 'true', expected_client_found: 'false'});
}

const tests = input.tests || testCases.slice(0, limit);
const batches = [];
for (let i = 0; i < tests.length; i += batchSize) {
  batches.push({batch_id: Math.floor(i / batchSize) + 1, tests: tests.slice(i, i + batchSize), target_url: targetWorkflowUrl});
}

return [{json: {total_tests: tests.length, batch_count: batches.length, batch_size: batchSize, target_url: targetWorkflowUrl, batches: batches, started_at: new Date().toISOString()}}];

const allBatches = $input.all();
const allBatchResults = [];
for (const batchItem of allBatches) {
  const batch = batchItem.json;
  const batchResults = [];
  for (const test of batch.tests) {
    const startTime = Date.now();
    try {
      const response = await this.helpers.httpRequest({method: 'POST', url: batch.target_url, body: { phone: test.input_phone || '', email: test.input_email || '' }, headers: { 'Content-Type': 'application/json' }, json: true});
      const elapsed = Date.now() - startTime;
      const actualSuccess = response.success === true;
      const expectedSuccess = test.expected_success === 'true';
      const actualFound = response.client !== null && response.client !== undefined;
      const expectedFound = test.expected_client_found === 'true';
      const passed = actualSuccess === expectedSuccess && actualFound === expectedFound;
      batchResults.push({test_id: test.id, category: test.category, passed: passed, elapsed_ms: elapsed, actual: { success: actualSuccess, client_found: actualFound }, expected: { success: expectedSuccess, client_found: expectedFound }});
    } catch (error) {
      batchResults.push({test_id: test.id, category: test.category, passed: false, error: error.message, elapsed_ms: Date.now() - startTime});
    }
  }
  allBatchResults.push({json: {batch_id: batch.batch_id, results: batchResults, passed: batchResults.filter(r => r.passed).length, failed: batchResults.filter(r => !r.passed).length}});
}
return allBatchResults;

const allResults = [];
let totalPassed = 0;
let totalFailed = 0;
for (const item of $input.all()) {
  const batch = item.json;
  allResults.push(...batch.results);
  totalPassed += batch.passed;
  totalFailed += batch.failed;
}
const failures = allResults.filter(r => !r.passed);
const failuresByCategory = {};
for (const f of failures) {
  failuresByCategory[f.category] = failuresByCategory[f.category] || [];
  failuresByCategory[f.category].push(f);
}
const totalTests = totalPassed + totalFailed;
const passRate = totalTests > 0 ? ((totalPassed / totalTests) * 100).toFixed(1) : '0.0';
const avgLatency = allResults.length > 0 ? allResults.reduce((sum, r) => sum + (r.elapsed_ms || 0), 0) / allResults.length : 0;
return [{json: {summary: {total_tests: totalTests, passed: totalPassed, failed: totalFailed, pass_rate: passRate + '%', avg_latency_ms: Math.round(avgLatency)}, failures_by_category: failuresByCategory, failure_count: failures.length, needs_autocorrection: totalFailed > 0, completed_at: new Date().toISOString()}}];
